dtsPropsFor.ConnectCard:
/** Connection lifecycle stage driving the status dot, label, and button fill. */
status: 'disconnected' | 'preparing' | 'connecting' | 'connected' | 'disconnecting' | 'failed';
/** Resolved exit location (e.g. "Tokyo, Japan"); null shows the auto-relay line. */
relayLabel: string | null;
isConnected: boolean;
isWorking: boolean;
onToggle: () => void;

dtsPropsFor.ConsolePanel:
/** "[HH:mm:ss] message" lines, newest last; empty shows the ready placeholder. */
logLines: string[];
/** Appended as an "! error" line in console-error red; null hides it. */
lastError: string | null;
/** Shows a dim "[mock native module]" notice (Debug screen, mock fallback). */
showMockNotice?: boolean;
style?: object;

dtsPropsFor.HomeIcon:
color: string;
size?: number;
strokeWidth?: number;

dtsPropsFor.InfoIcon:
color: string;
size?: number;
strokeWidth?: number;

dtsPropsFor.ListIcon:
color: string;
size?: number;
strokeWidth?: number;

dtsPropsFor.MapIcon:
color: string;
size?: number;
strokeWidth?: number;

dtsPropsFor.MapStatusChip:
directoryStatus: 'idle' | 'loading' | 'loaded' | 'failed';
regionCount: number;
/** Tapped in the failed / loaded-but-empty states. */
onRetry: () => void;
style?: object;

dtsPropsFor.OceanTelemetry:
regions: Array<{ countryCode: string; countryName: string; city: string | null; latitude: number; longitude: number; nodeCount: number; relays: Array<{ id: string; label: string | null }> }>;
directoryStatus: 'idle' | 'loading' | 'loaded' | 'failed';
status: 'disconnected' | 'preparing' | 'connecting' | 'connected' | 'disconnecting' | 'failed';
/** Resolved exit location while connected; null shows the auto-relay target. */
relayLabel: string | null;
/** Already-localized native error line, shown only in the failed state. */
lastError: string | null;
/** Native activity log — mined for the id of the relay the tunnel dialled. */
logLines: string[];
/** Epoch ms when the tunnel entered 'connected'; null while down. Drives the uptime clock. */
connectedAtMs: number | null;

dtsPropsFor.PowerIcon:
color: string;
size?: number;
strokeWidth?: number;

dtsPropsFor.RecentsSection:
/** Recent connections, newest first; empty renders nothing at all. */
recents: Array<{ countryCode: string; label: string; latitude: number; longitude: number }>;
onPress: (countryCode: string) => void;

dtsPropsFor.RelayList:
regions: Array<{ countryCode: string; countryName: string; city: string | null; latitude: number; longitude: number; nodeCount: number; relays: Array<{ id: string; label: string | null }> }>;
directoryStatus: 'idle' | 'loading' | 'loaded' | 'failed';
/** Connect to one specific volunteer relay (picked from an expanded location row). */
onRelayPress: (relayId: string, countryCode: string) => void;
onRetry: () => void;
style?: object;

dtsPropsFor.SettingPanel:
title: string;
subtitle: string;
/** When set the row is pressable and shows a terminal-green chevron. */
onPress?: () => void;
/** Custom trailing element (replaces the chevron). */
trailing?: React.ReactNode;

dtsPropsFor.SlidersIcon:
color: string;
size?: number;
strokeWidth?: number;
